 1	import * as React from 'react';
 2	import { Modal, Button, ButtonVariant } from '@patternfly/react-core';
 3	import { AuthStrategy } from '../../types/Auth';
 4	import { LoginSession } from '../../store/Store';
 5	import { authenticationConfig } from '../../config/AuthenticationConfig';
 6	import { PFColors } from 'components/Pf/PfColors';
 7	import { kialiStyle } from 'styles/StyleUtils';
 8	import { KialiIcon } from 'config/KialiIcon';
 9	
10	type SessionTimeoutProps = {
11	  onDismiss: () => void;
12	  onExtendSession: (session: LoginSession) => void;
13	  onLogout: () => void;
14	  show: boolean;
15	  timeOutCountDown: number;
16	};
17	
18	const sessionTimeoutStyle = kialiStyle({
19	  marginBottom: '1.5rem',
20	  fontSize: '18px',
21	  lineHeight: 1.4
22	});
23	
24	export const SessionTimeout: React.FC<SessionTimeoutProps> = (props: SessionTimeoutProps) => {
25	  const textForAuthStrategy = (_strategy: AuthStrategy): React.ReactNode => {
26	    const line1 =
27	      props.timeOutCountDown <= 0
28	        ? 'Your session has expired.'
29	        : `Your session will expire in ${props.timeOutCountDown.toFixed()} seconds.`;
30	
31	    const line2 = 'You will need to re-login. Please save your changes, if any.';
32	
33	    return (
34	      <>
35	        <div>{line1}</div>
36	        <div>{line2}</div>
37	      </>
38	    );
39	  };
40	
41	  const defaultAction = props.onDismiss;
42	
43	  const buttons = [
44	    <Button autoFocus={true} variant={ButtonVariant.primary} onClick={props.onDismiss}>
45	      OK
46	    </Button>,
47	    <Button
48	      data-test="session-timeout-logout-btn"
49	      key="confirm"
50	      variant={ButtonVariant.secondary}
51	      onClick={props.onLogout}
52	    >
53	      Log Out
54	    </Button>
55	  ];
56	
57	  return (
58	    <Modal
59	      data-test="session-timeout-modal"
60	      isOpen={props.show}
61	      onClose={defaultAction}
62	      actions={buttons}
63	      title="Session Timeout"
64	      width="40%"
65	    >
66	      <span>
67	        <KialiIcon.Warning size="xl" color={PFColors.Warning} />
68	      </span>
69	
70	      <span style={{ float: 'right', width: '80%' }} className={sessionTimeoutStyle}>
71	        {textForAuthStrategy(authenticationConfig.strategy)}
72	      </span>
73	    </Modal>
74	  );
75	};

